#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n , m;
int a[500005];
int c[500005];
int lowbit (int x) {
	return x & (-x);
} 
void update (int i , int k) {
	for (; i <= n; i += lowbit(i)) {
		c[i] += k;
	}
}
int getsum (int i) {
	int ans = 0;
	for (; i > 0; i -= lowbit(i)) {
		ans += c[i];
	}
	return ans;
}
signed main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		update( i , a[i] );
	}
	for (int i = 1 , op , x , y; i <= m; i++) {
		cin >> op >> x >> y; 
		if (op == 1) {
			update(x , y);
		} else {
			cout << getsum(y) - getsum(x - 1) << '\n';
		}
	}
	return 0;
}
